CODE_EXAMPLE:
// Before (smell)
double getSpeed() {
  switch (type) {
    case EUROPEAN: return getBaseSpeed();
    case AFRICAN: return getBaseSpeed() - getLoadFactor() * numberOfCoconuts;
    case NORWEGIAN_BLUE: return isNailed ? 0 : getBaseSpeed();
  }
}

// After (refactored - polymorphism)
abstract class Bird {
  abstract double getSpeed();
}

class EuropeanBird extends Bird {
  double getSpeed() { return getBaseSpeed(); }
}

UNIT_TEST_EXAMPLE:
@Test
public void testSwitchSmell() {
  Bird bird = new EuropeanBird();
  assertTrue(bird.getSpeed() > 0);
}
